head.script:
scwin.strCurDate = WebSquare.date.getCurrentServerDate();  // 서버를 기준으로 현재 날짜 반환
scwin.strQryStDt = scwin.strCurDate.substring(0, 6) + "01"; // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)



scwin.memJson = $c.data.getMemInfo();
scwin.userId = scwin.memJson.userId;  //사용자

scwin.onpageload = function () {

    ed_dtFrom.setValue(scwin.strQryStDt);
    ed_slipDt.setValue(scwin.strCurDate);
    chk_slipNoYn.setValue("");
};

scwin.onUdcCompleted = async function () {
    gr_out.setColumnStyle("vehclSlipNo", "text-decoration", "underline");
    gr_out.setColumnStyle("vehclSlipNo", "color", "blue");
    gr_out.setColumnStyle("vehclSlipNo", "cursor", "pointer");
}

//초기화
scwin.btn_fieldClear_onclick = function (e) {

    $c.gus.cfInitObjects(portCondtionPart, null);
};

//거래처 pop

scwin.udc_comCode_clnt_onclickEvent = function (e) {

    udc_comCode_clnt.cfCommonPopUp(scwin.udc_comCode_clnt_callBackFunc, ed_clntNo.getValue(), ed_clntNm.getValue(), "T", "5", null, null, null, null, null, null, null, null, null, "F", "소속거래처,거래처코드,거래처명", null);
};

scwin.udc_comCode_clnt_callBackFunc = function (ret) {

    $c.gus.cfSetReturnValue(ret, ed_clntNo, ed_clntNm);
    console.log(ret);
};
scwin.udc_comCode_clnt_onblurCodeEvent = function (e) {

    if (ed_clntNo.getValue() === "") {

        ed_clntNm.setValue("");
    } else {

        udc_comCode_clnt.cfCommonPopUp(scwin.udc_comCode_clnt_callBackFunc, ed_clntNo.getValue(), ed_clntNm.getValue(), "T", "5", null, null, null, null, null, null, null, null, null, "F", "소속거래처,거래처코드,거래처명", null);
    }
};

scwin.udc_comCode_clnt_onviewchangeNameEvent = function (info) {

    if (ed_clntNm.getValue() === "") {

        ed_clntNo.setValue("");
    }
};

//차량번호 pop
scwin.udc_comCode_vehcl_onclickEvent = function (e) {

    udc_comCode_vehcl.cfCommonPopUp(scwin.udc_comCode_vehcl_callBackFunc, vehclNoCd.getValue(), cond_vehclNo.getValue(), "T", null, null, null, null, null, null, null, null, null, null, "T", "차량번호,차량단축코드,차량번호", null);
};

scwin.udc_comCode_vehcl_callBackFunc = function (ret) {

    $c.gus.cfSetReturnValue(ret, vehclNoCd, cond_vehclNo);
    console.log(ret);
};

scwin.udc_comCode_vehcl_onblurCodeEvent = function (e) {

    if (vehclNoCd.getValue() === "") {

        cond_vehclNo.setValue("");
    } else {

        udc_comCode_vehcl.cfCommonPopUp(scwin.udc_comCode_vehcl_callBackFunc, vehclNoCd.getValue(), cond_vehclNo.getValue(), "T", null, null, null, null, null, null, null, null, null, null, "T", "차량번호,차량단축코드,차량번호", null);
    }
};

scwin.udc_comCode_vehcl_onviewchangeNameEvent = function (info) {

    if (cond_vehclNo.getValue() === "") {

        vehclNoCd.setValue("");
    }
};

//조회
scwin.btn_retrieve_onclick = async function (e) {

    if ((ed_dtFrom.getValue() == "")) {
        await $c.win.alert("년월은 필수조건 입니다.");
        ed_dtFrom.focus();
        return;
    }

    //dataMap Binding...
    dma_condition.set("adptYm", ed_dtFrom.getValue());
    dma_condition.set("vehclNoCd", cond_vehclNo.getValue());
    dma_condition.set("pchsClntNo", ed_clntNo.getValue());
    dma_condition.set("slipNo", ed_slipNo.getValue());
    dma_condition.set("slipNoYn", chk_slipNoYn.getValue());

    $c.sbm.execute(sbm_retrieve);
};

//조회 callback
scwin.sbm_retrieve_submitdone = async function () {

    let nCnt = ds_out.getRowCount();

    if (nCnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    } else {
        gr_out.setFocusedCell(0, 0);
        total.setValue(nCnt);

        for (var i = 0; i < ds_out.getRowCount(); i++) {
            if (ds_out.getCellData(i, "realPayAmt")) {
            }

            ds_out.setCellData(i, "realPayAmt", 0);
        }
    }
};

//전표일자 일괄적용
scwin.btn_adaptSlipDt_onclick = async function (e) {

    let chkCnt = 0;
    let slipDt = ed_slipDt.getValue();

    for (var i = 0; i < ds_out.getRowCount(); i++) {
        if (ds_out.getCellData(i, "choice") == 1) {
            ds_out.setCellData(i, "vehclSlipDt", slipDt);
            chkCnt++;
        }
    }
    if (chkCnt == 0) {
        await $c.win.alert("선택된 행이 없습니다. 일괄적용할 행들을 선택해 주십시오.");
        return;
    }
};

//전표삭제 btn
scwin.btn_delete_onclick = async function (e) {

    let confirm = await $c.win.confirm("전표를 삭제 하시겠습니까?")

    if (confirm) {
        ds_process.removeAll();

        let j = 0;
        for (var i = 0; i < ds_out.getRowCount(); i++) {
            if (ds_out.getCellData(i, "choice") == 1) {

                //전표번호가 없는건은 삭제 할 수 없다.
                if (ds_out.getCellData(i, "vehclSlipNo") == "") {
                    await $c.win.alert((i + 1) + "번째 건은 삭제 할 수 없습니다..\n\n미발생 전표 삭제 불가!");
                    return;
                }

                scwin.f_SetDataSet(i, j);
                j++;
            }
        }

        if (j == 0) {
            await $c.win.alert("선택된건이 없습니다.");
            return;
        }
        $c.sbm.execute(sbm_delete);
    }
};

//-------------------------------------------------------------------------
// Save or Del DataSet Setting
//-------------------------------------------------------------------------
scwin.f_SetDataSet = function (row, col) {

    ds_process.insertRow();

    ds_process.setCellData(col, "slipNo", ds_out.getCellData(row, "vehclSlipNo"));	        //전표번호
    ds_process.setCellData(col, "clntNo", ds_out.getCellData(row, "homeClntNo")); 	        //소속거래처코드
    ds_process.setCellData(col, "clntNm", ds_out.getCellData(row, "homeClntNm")); 	        //소속거래처명
    ds_process.setCellData(col, "vehclNo", ds_out.getCellData(row, "vehclNo"));		    //차량번호
    ds_process.setCellData(col, "pchsClntNo", ds_out.getCellData(row, "pchsClntNo")); 	    //매니저코드
    ds_process.setCellData(col, "pchsClntNm", ds_out.getCellData(row, "pchsClntNm")); 	    //매니저명
    ds_process.setCellData(col, "amt", ds_out.getCellData(row, "payAmt")); 		        //실지급액
    ds_process.setCellData(col, "slipDt", ds_out.getCellData(row, "vehclSlipDt"));	        //작성일자
    ds_process.setCellData(col, "adptYm", ds_out.getCellData(row, "adptYm"));	            //년월
};

scwin.f_SetDataSet2 = function (row, col) {

    ds_process.insertRow();

    ds_process.setCellData(col, "slipNo", ds_out.getCellData(row, "vehclSlipNo"));	        //전표번호
    ds_process.setCellData(col, "clntNo", ds_out.getCellData(row, "homeClntNo")); 	        //소속거래처코드
    ds_process.setCellData(col, "clntNm", ds_out.getCellData(row, "homeClntNm")); 	        //소속거래처명
    ds_process.setCellData(col, "vehclNo", ds_out.getCellData(row, "vehclNo"));		    //차량번호
    ds_process.setCellData(col, "pchsClntNo", ds_out.getCellData(row, "pchsClntNo"));  	//매니저코드
    ds_process.setCellData(col, "pchsClntNm", ds_out.getCellData(row, "pchsClntNm"));  	//매니저명
    ds_process.setCellData(col, "amt", ds_out.getCellData(row, "payAmt")); 		        //실지급액
    ds_process.setCellData(col, "slipDt", ds_out.getCellData(row, "vehclSlipDt"));	        //작성일자
    ds_process.setCellData(col, "adptYm", ds_out.getCellData(row, "adptYm"));	            //년월

    ds_process.setCellData(col, "deductNoPchsAmt", ds_out.getCellData(row, "deductNoPchsAmt"));	//지급내역
    ds_process.setCellData(col, "deductPchsAmt", ds_out.getCellData(row, "deductPchsAmt"));	    //공제내역
    ds_process.setCellData(col, "bankNm", ds_out.getCellData(row, "bankNm"));	                    //은행명
    ds_process.setCellData(col, "bankAcntNo", ds_out.getCellData(row, "bankAcntNo"));	            //계좌번호
    ds_process.setCellData(col, "dpstrNm", ds_out.getCellData(row, "dpstrNm"));	                //예금주
    ds_process.setCellData(col, "Apply", ds_out.getCellData(row, "Apply"));	                    //메일전송 구분값

};

//grid onclick event
scwin.gr_out_oncellclick = function (rowIndex, columnIndex, columnId) {

    let tempVehclNo = ds_out.getCellData(rowIndex, 'vehclNo');
    let flag = false;

    for (i = 0; i < ds_out.getRowCount(); i++) {

        if (ds_out.getCellData(i, 'vehclNo') == tempVehclNo && flag == false) {
            flag = true;
        }

        if (ds_out.getCellData(i, 'vehclNo') != tempVehclNo && flag == true) {
            flag = false;
            eIndex = i - 1;
        }
    }

    //grid 전표번호 클릭시
    if (columnId == "vehclSlipNo" && rowIndex > 0) {
        if (!(ds_out.getCellData(rowIndex, "vehclSlipNo") == null || ds_out.getCellData(rowIndex, "vehclSlipNo") == "")) {
            $c.gus.cfShowSlipInfo(ds_out.getCellData(rowIndex, "vehclSlipNo"));
        }
    }
};

//전표생성 btn
scwin.btn_save_onclick = async function (e) {

    let confirm = await $c.win.confirm("전표생성 하시겠습니까?")

    if (confirm) {
        ds_process.removeAll();
        let j = 0;
        for (var i = 0; i < ds_out.getRowCount(); i++) {
            if (ds_out.getCellData(i, "choice") == 1) {

                //이미 전표생성된 건은 처리 못한다.
                if (ds_out.getCellData(i, "vehclSlipNo") != "") {
                    await $c.win.alert((i + 1 ) + "번째 건은 이미 전표생성 되었습니다.\n\n중복생성 불가!");
                    return;
                }

                //전표날짜 세팅이 안된건은 처리 못한다.
                //if(ds_out.getCellData(i,"slipDt") == "" || $c.gus.cfIsNull(ds_out.getCellData(i,"vehclSlipDt")))
                if ($c.gus.cfIsNull(ds_out.getCellData(i, "vehclSlipDt"))) {
                    await $c.win.alert((i + 1 ) + "번째 건은 작성일자가 없습니다.");
                    return;
                }

                //실지급액이 마이너스인 건은 처리 못한다.
                if (ds_out.getCellData(i, "payAmt") < 0) {
                    await $c.win.alert((i + 1) +"번째 건은 실지급액이 마이너스입니다.\n\n전표생성 불가!");
                    return;
                }

                scwin.f_SetDataSet(i, j);
                j++;
            }
        }

        if (j == 0) {
            await $c.win.alert("선택된건이 없습니다.");
            return;
        }
        $c.sbm.execute(sbm_save);
    }
};

//메일전송추가 전송
scwin.btn_send_onclick = async function (e) {

    let confirm = await $c.win.confirm("명세서를  메일전송 하시겠습니까?")
    if (confirm) {
        ds_process.removeAll();
        let j = 0;
        for (var i = 0; i < ds_out.getRowCount(); i++) {
            if (ds_out.getCellData(i, "choice") == 1) {

                scwin.f_SetDataSet2(i, j);
                j++;
            }
        }

        if (j == 0) {
            await $c.win.alert("선택된건이 없습니다.");
            return;
        }
        $c.sbm.execute(sbm_apply);
    }
};

//발행(print)
scwin.btn_print_onclick = async function (e) {

    let j = 0;
    let reportName_url = "";
    ds_oz.removeAll();

    for (var i = 0; i < ds_out.getRowCount(); i++) {
        if (ds_out.getCellData(i, "choice") == 1) {
            ds_oz.insertRow();
            ds_oz.setCellData(j, "vehclNo", ds_out.getCellData(i, "vehclNo"));
            ds_oz.setCellData(j, "homeClntNo", ds_out.getCellData(i, "homeClntNo"));
            ds_oz.setCellData(j, "pchsClntNo", ds_out.getCellData(i, "pchsClntNo"));
            ds_oz.setCellData(j, "adptYm", ds_out.getCellData(i, "adptYm"));
            j++
        }
    }

    let chkAdptYm = ds_oz.getCellData(0, "adptYm");
    let total = ds_oz.getRowCount();

    if (total == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["월급명세서"]);
        return;
    }

    let remain = total % 2; //나머지
    let lastTarget = "";

    if (remain == 0) {
        lastTarget = "";
    } else {
        lastTarget = total;
    }
    for (var i = 0; i < ds_oz.getRowCount(); i++) {
        if (i+1 < total) {

            // 쿼리(ODI)에 적용할 파라미터를 설정(OZParam)
            if (chkAdptYm == "201706") {
                reportName_url = "/ja/dn/workrslts/ja_400_01_03b_A_6.ozr"
            } else {
                reportName_url = "/ja/dn/workrslts/ja_400_01_03b_A.ozr"
            }
            data = {
                odiName : "ja_400_01_03b_A",
                reportName: reportName_url,
                odiParam: {
                    vehclNo: ds_oz.getCellData(i, "vehclNo"),
                    homeClntNo: ds_oz.getCellData(i, "homeClntNo"),
                    pchsClntNo: ds_oz.getCellData(i, "pchsClntNo"),
                    adptYm: ds_oz.getCellData(i, "adptYm"),
                    vehclNo2: ds_oz.getCellData(i + 1, "vehclNo"),
                    homeClntNo2: ds_oz.getCellData(i + 1, "homeClntNo"),
                    pchsClntNo2: ds_oz.getCellData(i + 1, "pchsClntNo"),
                    adptYm2: ds_oz.getCellData(i + 1, "adptYm"),
                    coCd: "000",

                },
                viewerParam: {
                    useprogressbar: false,
                    mode: "silent"
                },
                formParam: {
                }
            }
            if (chb_previewCheck.getValue() == "1") {
                let opts = {
                    "type": 'viewer',
                    "printMode": 'view'
                };
                await $c.ext.openOzReport(data, opts);
            } else {

                await $c.ext.printOzReport(data);
            }

            i++;
        }
        if (i+1 == total && i+1== lastTarget) {

            // 쿼리(ODI)에 적용할 파라미터를 설정(OZParam)
            if (chkAdptYm == "201706") {
                reportName_url = "/ja/dn/workrslts/ja_400_01_03b_B_6.ozr"
            } else {
                reportName_url = "/ja/dn/workrslts/ja_400_01_03b_B.ozr"
            }
            data = {
                odiName : "ja_400_01_03b_A",
                reportName: reportName_url,
                odiParam: {
                    vehclNo: ds_oz.getCellData(i, "vehclNo"),
                    homeClntNo: ds_oz.getCellData(i, "homeClntNo"),
                    pchsClntNo: ds_oz.getCellData(i, "pchsClntNo"),
                    adptYm: ds_oz.getCellData(i, "adptYm"),
                    coCd: "000",

                },
                viewerParam: {
                    useprogressbar: false,
                    // mode: "silent"
                },
                formParam: {
                }
            }
            if (chb_previewCheck.getValue() == "1") {
                let opts = {
                    "type": 'viewer',
                    "printMode": 'view'
                };
                await $c.ext.openOzReport(data, opts);
            } else {

                await $c.ext.printOzReport(data);
            }

            i++;
        }
    }
};

scwin.f_Excel = async function () {
    if (ds_out.getTotalRow() == 0) {
        return;
    }

    const infoArr = [];
    const options = {
        fileName : "차량별 급여명세 현황.xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        sheetName: "차량별 급여명세 현황",
        type : "1",
        // startRowIndex: 2,
        // removeColumns: "0,21",
        // hiddenVisible : true,
        // useSubTotal :"true", 
        // useSubTotalData  : "true",
        // oddRowBackgroundColor  : "",                        // excel파일에서 그리드 body의 홀수줄의 배경색
        // evenRowBackgroundColor : "#F5FFF5"                  // excel파일에서 그리드 body의 짝수줄의 배경색
    };
    $c.data.downloadGridViewExcel(gr_out, options, infoArr);


}

scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);
        // scwin.f_Retrieve();
        scwin.btn_retrieve_onclick();

    }
};

scwin.sbm_delete_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);
        // f_Retrieve();
        scwin.btn_retrieve_onclick();
    }
};

scwin.sbm_apply_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code == 0) {
        await $c.win.alert("메일전송성공");
        // f_Retrieve();
        scwin.btn_retrieve_onclick();
    }
};
